@@ -486,3 +486,1274 @@ module BRAM2x18_SDP (A1ADDR, A1DATA, A1EN, B1ADDR, B1DATA, B1EN, C1ADDR, C1DATA,
 		.FLUSH2_i(FLUSH2)
 	);
 endmodule
